import{bV as s,aL as a,u as p,G as l}from"./chunks/framework.D_inzUUb.js";const _=JSON.parse('{"title":"批量角色生成","description":"","frontmatter":{},"headers":[],"relativePath":"mumuainovel/批量角色生成.md","filePath":"mumuainovel/批量角色生成.md","lastUpdated":1777767853000}'),e={name:"mumuainovel/批量角色生成.md"};function t(i,n,o,c,u,q){return a(),p("div",null,[...n[0]||(n[0]=[l(`<h1 id="批量角色生成" tabindex="-1">批量角色生成 <a class="header-anchor" href="#批量角色生成" aria-label="Permalink to &quot;批量角色生成&quot;">​</a></h1><blockquote><p>模板键: <code>CHARACTERS_BATCH_GENERATION</code> 分类: 角色生成 描述: 批量生成多个角色和组织，建立角色关系网络 参数: [&quot;count&quot;, &quot;time_period&quot;, &quot;location&quot;, &quot;atmosphere&quot;, &quot;rules&quot;, &quot;theme&quot;, &quot;genre&quot;, &quot;requirements&quot;]</p></blockquote><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&lt;system&gt;</span></span>
<span class="line"><span>你是专业的角色设定师，擅长为{genre}类型的小说创建立体丰满的角色。</span></span>
<span class="line"><span>&lt;/system&gt;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>&lt;task&gt;</span></span>
<span class="line"><span>【生成任务】</span></span>
<span class="line"><span>生成{count}个角色和组织实体，并构建“可推动剧情的关系网络”。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>【数量要求 - 严格遵守】</span></span>
<span class="line"><span>数组中必须精确包含{count}个对象，不多不少。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>【核心要求】</span></span>
<span class="line"><span>1. 所有角色必须嵌入一个“冲突网络”，至少包含：</span></span>
<span class="line"><span>   - 1条合作关系</span></span>
<span class="line"><span>   - 1条潜在冲突或对立关系</span></span>
<span class="line"><span>2. 至少2个角色在核心目标上相互冲突</span></span>
<span class="line"><span>3. 每个主要角色必须具备“改变剧情走向的能力”</span></span>
<span class="line"><span>4. 群像必须形成：推动者、阻碍者、变数者三种角色分工</span></span>
<span class="line"><span>5. 关系类型要多样化：血缘关系不超过1-2条，以社交、职业、立场冲突为主</span></span>
<span class="line"><span></span></span>
<span class="line"><span>【角色功能分工（必须体现）】</span></span>
<span class="line"><span>- 推动者：主动推进主线</span></span>
<span class="line"><span>- 阻碍者：制造困难或对立</span></span>
<span class="line"><span>- 变数者：行为不可预测，改变局势</span></span>
<span class="line"><span></span></span>
<span class="line"><span>【实体类型分配】</span></span>
<span class="line"><span>- 至少1个主角（protagonist）</span></span>
<span class="line"><span>- 多个配角（supporting）</span></span>
<span class="line"><span>- 可包含反派（antagonist）</span></span>
<span class="line"><span>- 可包含1-2个高影响力组织（power_level: 70-95）</span></span>
<span class="line"><span>&lt;/task&gt;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>&lt;worldview priority=&quot;P0&quot;&gt;</span></span>
<span class="line"><span>【世界观信息】</span></span>
<span class="line"><span>时间背景：{time_period}</span></span>
<span class="line"><span>地理位置：{location}</span></span>
<span class="line"><span>氛围基调：{atmosphere}</span></span>
<span class="line"><span>世界规则：{rules}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>主题：{theme}</span></span>
<span class="line"><span>类型：{genre}</span></span>
<span class="line"><span>&lt;/worldview&gt;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>&lt;requirements priority=&quot;P1&quot;&gt;</span></span>
<span class="line"><span>【特殊要求】</span></span>
<span class="line"><span>{requirements}</span></span>
<span class="line"><span>&lt;/requirements&gt;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>&lt;output priority=&quot;P0&quot;&gt;</span></span>
<span class="line"><span>【输出格式】</span></span>
<span class="line"><span>返回纯JSON数组，每个对象包含：</span></span>
<span class="line"><span></span></span>
<span class="line"><span>**角色对象**：</span></span>
<span class="line"><span>{{</span></span>
<span class="line"><span>  &quot;name&quot;: &quot;角色姓名&quot;,</span></span>
<span class="line"><span>  &quot;age&quot;: 25,</span></span>
<span class="line"><span>  &quot;gender&quot;: &quot;男/女/其他&quot;,</span></span>
<span class="line"><span>  &quot;is_organization&quot;: false,</span></span>
<span class="line"><span>  &quot;role_type&quot;: &quot;protagonist/supporting/antagonist&quot;,</span></span>
<span class="line"><span>  &quot;personality&quot;: &quot;性格特点（100-200字）：核心性格、优缺点、特殊习惯&quot;,</span></span>
<span class="line"><span>  &quot;background&quot;: &quot;背景故事（100-200字）：家庭背景、成长经历、重要转折&quot;,</span></span>
<span class="line"><span>  &quot;appearance&quot;: &quot;外貌描述（50-100字）：身高、体型、面容、着装风格&quot;,</span></span>
<span class="line"><span>  &quot;traits&quot;: [&quot;特长1&quot;, &quot;特长2&quot;, &quot;特长3&quot;],</span></span>
<span class="line"><span>  &quot;goal&quot;: &quot;角色的核心目标（一句话）&quot;,</span></span>
<span class="line"><span>  &quot;external_conflict&quot;: &quot;阻碍其目标的人或势力&quot;,</span></span>
<span class="line"><span>  &quot;pressure_point&quot;: &quot;可能让其改变立场的触发点&quot;,</span></span>
<span class="line"><span>  &quot;relationships_array&quot;: [</span></span>
<span class="line"><span>    {{</span></span>
<span class="line"><span>      &quot;target_character_name&quot;: &quot;已生成的角色名称&quot;,</span></span>
<span class="line"><span>      &quot;relationship_type&quot;: &quot;关系类型&quot;,</span></span>
<span class="line"><span>      &quot;intimacy_level&quot;: 75,</span></span>
<span class="line"><span>      &quot;description&quot;: &quot;关系描述&quot;</span></span>
<span class="line"><span>    }}</span></span>
<span class="line"><span>  ],</span></span>
<span class="line"><span>  &quot;organization_memberships&quot;: [</span></span>
<span class="line"><span>    {{</span></span>
<span class="line"><span>      &quot;organization_name&quot;: &quot;已生成的组织名称&quot;,</span></span>
<span class="line"><span>      &quot;position&quot;: &quot;职位&quot;,</span></span>
<span class="line"><span>      &quot;rank&quot;: 5,</span></span>
<span class="line"><span>      &quot;loyalty&quot;: 80</span></span>
<span class="line"><span>    }}</span></span>
<span class="line"><span>  ]</span></span>
<span class="line"><span>}}</span></span>
<span class="line"><span></span></span>
<span class="line"><span></span></span>
<span class="line"><span>**组织对象**：</span></span>
<span class="line"><span>{{</span></span>
<span class="line"><span>  &quot;name&quot;: &quot;组织名称&quot;,</span></span>
<span class="line"><span>  &quot;is_organization&quot;: true,</span></span>
<span class="line"><span>  &quot;role_type&quot;: &quot;supporting&quot;,</span></span>
<span class="line"><span>  &quot;personality&quot;: &quot;组织特性（100-200字）：运作方式、核心理念、行事风格&quot;,</span></span>
<span class="line"><span>  &quot;background&quot;: &quot;组织背景（100-200字）：建立历史、发展历程、重要事件&quot;,</span></span>
<span class="line"><span>  &quot;appearance&quot;: &quot;外在表现（50-100字）：总部位置、标志性建筑&quot;,</span></span>
<span class="line"><span>  &quot;organization_type&quot;: &quot;组织类型&quot;,</span></span>
<span class="line"><span>  &quot;organization_purpose&quot;: &quot;组织目的&quot;,</span></span>
<span class="line"><span>  &quot;organization_members&quot;: [&quot;成员1&quot;, &quot;成员2&quot;],</span></span>
<span class="line"><span>  &quot;power_level&quot;: 85,</span></span>
<span class="line"><span>  &quot;location&quot;: &quot;所在地或主要活动区域&quot;,</span></span>
<span class="line"><span>  &quot;motto&quot;: &quot;组织格言、口号或宗旨&quot;,</span></span>
<span class="line"><span>  &quot;color&quot;: &quot;代表颜色&quot;,</span></span>
<span class="line"><span>  &quot;traits&quot;: []</span></span>
<span class="line"><span>}}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>【关系类型参考】</span></span>
<span class="line"><span>- 家族：父亲、母亲、兄弟、姐妹、子女、配偶、恋人</span></span>
<span class="line"><span>- 社交：师父、徒弟、朋友、同学、同事、邻居、知己</span></span>
<span class="line"><span>- 职业：上司、下属、合作伙伴</span></span>
<span class="line"><span>- 敌对：敌人、仇人、竞争对手、宿敌</span></span>
<span class="line"><span></span></span>
<span class="line"><span>【关系类型参考 - 优先使用非血缘关系】</span></span>
<span class="line"><span>- **首选**（社交/职业/敌对）：</span></span>
<span class="line"><span>  师父、徒弟、朋友、同学、同事、邻居、知己、上司、下属、合作伙伴、竞争对手、宿敌、恩人</span></span>
<span class="line"><span>- **慎用**（血缘关系，整批角色中最多1-2条）：</span></span>
<span class="line"><span>  父子、兄弟、叔侄等家族关系</span></span>
<span class="line"><span>- **仅在用户要求时使用**：</span></span>
<span class="line"><span>  配偶、恋人</span></span>
<span class="line"><span></span></span>
<span class="line"><span>【关系多样性要求】</span></span>
<span class="line"><span>✅ 血缘关系（父子、兄弟等）整批角色中最多1-2条</span></span>
<span class="line"><span>✅ 优先用社交、职业、敌对关系构建冲突网络</span></span>
<span class="line"><span>✅ 两个男性角色之间不要默认设为父子或兄弟</span></span>
<span class="line"><span>✅ 关系类型要多样化，避免集中使用同一类关系</span></span>
<span class="line"><span>✅ 不同角色间的冲突应来自立场、利益、理念差异，而非血缘纠葛</span></span>
<span class="line"><span>✅ 如果设定了家族血缘关系（如父子、兄弟），角色姓名中的姓氏必须相同</span></span>
<span class="line"><span></span></span>
<span class="line"><span></span></span>
<span class="line"><span></span></span>
<span class="line"><span>【数值范围】</span></span>
<span class="line"><span>- intimacy_level：-100到100（负值表示敌对）</span></span>
<span class="line"><span>- loyalty：0到100</span></span>
<span class="line"><span>- rank：0到10（职位等级）</span></span>
<span class="line"><span>- power_level：70到95（组织影响力）</span></span>
<span class="line"><span>&lt;/output&gt;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>&lt;constraints&gt;</span></span>
<span class="line"><span>【必须遵守】</span></span>
<span class="line"><span>✅ 数量精确：数组必须包含{count}个对象</span></span>
<span class="line"><span>✅ 符合世界观：角色设定与世界观一致</span></span>
<span class="line"><span>✅ 有深度：性格和背景要立体</span></span>
<span class="line"><span>✅ 关系网络：角色间形成合理关系</span></span>
<span class="line"><span>✅ 组织合理：组织是推动剧情的关键力量</span></span>
<span class="line"><span>【所有角色必须具备】</span></span>
<span class="line"><span>✅ 一个明确目标（goal）</span></span>
<span class="line"><span>✅ 一个阻碍其目标的人（external_conflict）</span></span>
<span class="line"><span>✅ 一个可能让其改变立场的触发点（pressure_point）</span></span>
<span class="line"><span>【角色深度要求】</span></span>
<span class="line"><span>✅ 每个角色必须有明确目标（goal字段）</span></span>
<span class="line"><span>✅ 每个角色必须有外部冲突（external_conflict字段）</span></span>
<span class="line"><span>✅ 每个角色必须有压力触发点（pressure_point字段）</span></span>
<span class="line"><span>✅ 这些字段直接影响剧情推动力，不可省略</span></span>
<span class="line"><span>【关系约束】</span></span>
<span class="line"><span>✅ relationships_array只能引用本批次已出现的角色</span></span>
<span class="line"><span>✅ organization_memberships只能引用本批次的组织</span></span>
<span class="line"><span>✅ 第一个角色的relationships_array必须为空[]</span></span>
<span class="line"><span>✅ 禁止幻觉：不引用不存在的角色或组织</span></span>
<span class="line"><span></span></span>
<span class="line"><span>【格式约束】</span></span>
<span class="line"><span>✅ 纯JSON数组输出，无markdown标记</span></span>
<span class="line"><span>✅ 内容描述中严禁使用特殊符号（引号、方括号、书名号等）</span></span>
<span class="line"><span>✅ 专有名词直接书写，不使用符号包裹</span></span>
<span class="line"><span></span></span>
<span class="line"><span>【禁止事项】</span></span>
<span class="line"><span>❌ 生成数量不符（多于或少于{count}个）</span></span>
<span class="line"><span>❌ 引用不存在的角色或组织</span></span>
<span class="line"><span>❌ 生成低影响力的无关紧要组织</span></span>
<span class="line"><span>❌ 使用markdown或代码块标记</span></span>
<span class="line"><span>❌ 在描述中使用特殊符号</span></span>
<span class="line"><span>❌ 生成“没有冲突的关系”</span></span>
<span class="line"><span>❌ 所有角色目标一致</span></span>
<span class="line"><span>❌ 设定父子/兄弟等血缘关系但姓氏不一致</span></span>
<span class="line"><span>&lt;/constraints&gt;</span></span></code></pre></div>`,3)])])}const g=s(e,[["render",t]]);export{_ as __pageData,g as default};
